/**
 * Regenerates playground-default-presets.js from container-default-T.json / -V.json.
 * Run from repo root: node Sandbox/presets/build-playground-presets-js.cjs
 */
const fs = require("fs");
const path = require("path");

const dir = __dirname;
const t = JSON.parse(fs.readFileSync(path.join(dir, "container-default-T.json"), "utf8"));
const v = JSON.parse(fs.readFileSync(path.join(dir, "container-default-V.json"), "utf8"));

const payload = JSON.stringify({ T: t, V: v });
const out =
  "/* Generated by build-playground-presets-js.cjs — do not edit; run the script after changing container-default-*.json */\n" +
  "(function(g){\n" +
  "try{\n" +
  "g.__TG_CONTAINER_PRESETS__=" +
  payload +
  ";\n" +
  "}catch(_e){}\n" +
  '})(typeof globalThis!==\"undefined\"?globalThis:this);\n';

const outPath = path.join(dir, "playground-default-presets.js");
fs.writeFileSync(outPath, out, "utf8");
console.log("Wrote " + outPath);
